12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  const live = new Set<string>();
14	  for (const [x, y] of cells) {
15	    live.add(key(x, y));
16	  }
17	
18	  const neighborCounts = new Map<string, number>();
19	
20	  for (const k of live) {
21	    const [x, y] = parseKey(k);
22	    for (let dx = -1; dx <= 1; dx++) {
23	      for (let dy = -1; dy <= 1; dy++) {
24	        if (dx === 0 && dy === 0) continue;
25	        const nk = key(x + dx, y + dy);
26	        neighborCounts.set(nk, (neighborCounts.get(nk) ?? 0) + 1);
27	      }
28	    }
29	  }
30	
31	  const next: Cell[] = [];
32	  for (const [k, count] of neighborCounts) {
33	    const isAlive = live.has(k);
34	    if (isAlive && (count === 2 || count === 3)) {
35	      next.push(parseKey(k));
36	    } else if (!isAlive && count === 3) {
37	      next.push(parseKey(k));
38	    }
39	  }
40	
41	  return next;
42	}
